// ============================================
// PARSER LE MESSAGE WHATSAPP ENTRANT
// Compatible Meta Cloud API + WPPConnect
// ============================================
const body = $input.first().json;

// Supporter les 2 formats
let from, message, name;

// Format Meta Cloud API
if (body.entry) {
  const entry   = body.entry?.[0];
  const changes = entry?.changes?.[0];
  const value   = changes?.value;
  const msg     = value?.messages?.[0];
  const contact = value?.contacts?.[0];
  from    = msg?.from || '';
  message = msg?.text?.body || msg?.interactive?.button_reply?.title || '';
  name    = contact?.profile?.name || 'Client';
}
// Format WPPConnect / Baileys
else if (body.from) {
  from    = body.from.replace('@s.whatsapp.net', '');
  message = body.body || body.text || '';
  name    = body.sender?.pushname || 'Client';
}

const msgLower = message.toLowerCase().trim();

// Détecter l'intention
let intent = 'unknown';
let ville  = '';

// Mots clés intentions
if (/salut|bonjour|salam|ahlan|مرحبا|السلام/.test(msgLower)) {
  intent = 'greeting';
}
else if (/promo|promotion|offre|solde|عرض|تخفيض/.test(msgLower)) {
  intent = 'promo';
}
else if (/vendeur|vendor|poisson|سمك|بائع|كم الثمن|prix/.test(msgLower)) {
  intent = 'product';
}
else if (/livraison|توصيل|deliver/.test(msgLower)) {
  intent = 'delivery';
}
else if (/tanger|طنجة/.test(msgLower))  { intent = 'city'; ville = 'Tanger'; }
else if (/casa|دارالبيضاء|casablanca/.test(msgLower)) { intent = 'city'; ville = 'Casablanca'; }
else if (/rabat|رباط/.test(msgLower))   { intent = 'city'; ville = 'Rabat'; }
else if (/agadir|أكادير/.test(msgLower)) { intent = 'city'; ville = 'Agadir'; }
else if (/فين|وين|أين|where|localisation|ville|city/.test(msgLower)) {
  intent = 'location';
}
else if (/stop|désinscrire|unsubscribe/.test(msgLower)) {
  intent = 'stop';
}

return [{
  json: {
    from,
    name,
    message,
    intent,
    ville,
    timestamp: new Date().toISOString(),
    raw: body
  }
}];

// ============================================
// GÉNÉRER LA RÉPONSE WHATSAPP AUTOMATIQUE
// ============================================
const parsed  = $('🧠 Parser Message').first().json;
const promos  = $('🔥 Récupérer Promos API').first().json || [];
const vendeurs = $('👨‍🍳 Récupérer Vendeurs').first().json || [];

const { from, name, intent, ville } = parsed;
const prenom = name?.split(' ')[0] || 'صديقي';

let msgClient  = '';
let msgVendeur = '';
let notifierVendeur = false;

// ── RÉPONSES PAR INTENTION ───────────────────────────────────

if (intent === 'greeting') {
  msgClient = `🐟 *أهلاً ${prenom}!*

مرحباً بك في *SamakMarket* 🌊
السمك الطازج من البحر لديك مباشرة!

اختر ما يناسبك:
1️⃣ عروض اليوم 🔥
2️⃣ ابحث عن بائع قريب 📍
3️⃣ معلومات التوصيل 🚚

اكتب رقم اختيارك أو سؤالك بالعربية 😊`;
}

else if (intent === 'promo') {
  let liste = '';
  const promosList = Array.isArray(promos) ? promos.slice(0, 3) : [];

  if (promosList.length > 0) {
    promosList.forEach((p, i) => {
      liste += `\n${i+1}️⃣ *${p.name}* — ${p.price} MAD/${p.unit} 📍${p.city || 'Maroc'}`;
    });
    msgClient = `🔥 *عروض اليوم على SamakMarket!*
${liste}

✅ السمك طازج 100% من البحر مباشرة
👉 للطلب: ${process.env.FRONTEND_URL || 'http://localhost:5173'}

تريد تواصل مع البائع؟ اكتب *بائع* 👨‍🍳`;
  } else {
    msgClient = `🔥 *عروض اليوم*

ما كاينش عروض دابا، عاود جرب من بعد شوية!

👉 شوف جميع المنتجات: ${process.env.FRONTEND_URL || 'http://localhost:5173'}`;
  }
}

else if (intent === 'product' || intent === 'city') {
  const vendeursList = Array.isArray(vendeurs) ? vendeurs.slice(0, 3) : [];
  let listeV = '';

  if (vendeursList.length > 0) {
    vendeursList.forEach((v, i) => {
      listeV += `\n${i+1}️⃣ *${v.name}* — ${v.city}`;
      if (v.distance) listeV += ` (${v.distance} كم)`;
    });
    msgClient = `👨‍🍳 *البائعين القريبين منك${ville ? ' في ' + ville : ''}:*
${listeV}

📱 سنتواصل معك قريباً!
🛒 ${process.env.FRONTEND_URL || 'http://localhost:5173'}`;
    notifierVendeur = true;
  } else {
    msgClient = `👨‍🍳 ما لقيناش بائع قريب منك دابا.

عاود اكتب مدينتك:
🏙️ طنجة / كازا / رباط / أكادير

أو زور موقعنا:
👉 ${process.env.FRONTEND_URL || 'http://localhost:5173'}`;
  }

  // Message pour le vendeur
  if (notifierVendeur && vendeursList[0]) {
    msgVendeur = `🔔 *طلب جديد على SamakMarket!*

👤 *العميل:* ${name}
📱 *الهاتف:* ${from}${ville ? '\n📍 *المدينة:* ' + ville : ''}
⏰ *الوقت:* ${new Date().toLocaleTimeString('fr-FR')}

✅ تواصل معه قريباً!
_SamakMarket — للسمك الطازج_`;
  }
}

else if (intent === 'delivery') {
  msgClient = `🚚 *التوصيل على SamakMarket*

✅ توصيل سريع خلال 2-4 ساعات
📍 متوفر في: طنجة، كازا، رباط، أكادير
💰 التوصيل مجاني عند الطلب فوق 150 درهم

🛒 اطلب الآن:
👉 ${process.env.FRONTEND_URL || 'http://localhost:5173'}

أو تواصل مع البائع مباشرة 👨‍🍳`;
}

else if (intent === 'location') {
  msgClient = `📍 *أين تسكن؟*

اكتب مدينتك لنجد لك أقرب بائع سمك:

🏙️ *طنجة*
🏙️ *كازا*  
🏙️ *رباط*
🏙️ *أكادير*

أو أرسل موقعك الجغرافي 📌`;
}

else if (intent === 'stop') {
  msgClient = `تم إلغاء الاشتراك ✅

مع السلامة ${prenom}! 👋
إذا رجعت نحن هنا دائماً 🐟`;
}

else {
  msgClient = `🐟 *SamakMarket*

شكراً على تواصلك ${prenom}!

اكتب:
🔥 *عروض* — لعروض اليوم
👨‍🍳 *بائع* — للبائعين القريبين
🚚 *توصيل* — معلومات التوصيل

👉 ${process.env.FRONTEND_URL || 'http://localhost:5173'}`;
}

return [{
  json: {
    from,
    name,
    msgClient,
    msgVendeur,
    notifierVendeur,
    vendeurPhone: vendeurs?.[0]?.phone || vendeurs?.[0]?.whatsapp || null,
    intent,
    ville
  }
}];
